import{_ as e,o,c as t,a}from"./app.c11b95e6.js";const m=JSON.parse('{"title":"meat312 v. TheOrangeWizard, Jun 2018","description":"","frontmatter":{},"headers":[{"level":2,"title":"Case","slug":"case","link":"#case","children":[]},{"level":2,"title":"Proceedings","slug":"proceedings","link":"#proceedings","children":[]}],"relativePath":"government/court-cases-precedents/meat312_v_theorangewizard_jun_2018.md","lastUpdated":1666477380000}'),n={name:"government/court-cases-precedents/meat312_v_theorangewizard_jun_2018.md"},r=a('<h1 id="meat312-v-theorangewizard-jun-2018" tabindex="-1">meat312 v. TheOrangeWizard, Jun 2018 <a class="header-anchor" href="#meat312-v-theorangewizard-jun-2018" aria-hidden="true">#</a></h1><h2 id="case" tabindex="-1">Case <a class="header-anchor" href="#case" aria-hidden="true">#</a></h2><p>With Wingzero54 presiding, on 8th June 2018, meat312 demanded 24 diamonds in restitution from TheOrangeWizard for armour damage caused by mob spawns. TheOrangeWizard was ordered to finish placing torches in the Undercity within 48 hours, and to pay 4 diamonds in restitution.</p><h2 id="proceedings" tabindex="-1">Proceedings <a class="header-anchor" href="#proceedings" aria-hidden="true">#</a></h2><p><strong>meat312</strong>:</p><blockquote><p>I&#39;m suing TheOrangeWizard 24 diamonds for reparations to my armor due to the mobs continuing to spawn in the undercity. 24 because it has been 6 full days, and I have had 4 armor pieces damaged. I am also asking the court to please revisit the last trial.</p></blockquote><blockquote><p>But this time I will be asking for 40 diamonds due to it being 10 days since sentencing.</p></blockquote><p><strong>Wingzero54</strong>:</p><blockquote><p>TheOrangeWizard, will you pay Meat the reps for his armor?</p></blockquote><p><strong>TheOrangeWizard</strong>:</p><blockquote><p>Read above in this chat if you want to review my response to that opinion.</p></blockquote><p><strong>Wingzero54</strong>:</p><blockquote><p>You never made a comment in regards to meat wanting you to pay for his prot damage</p></blockquote><p><strong>TheOrangeWizard</strong>:</p><blockquote><p>depends, am I responsible for every instance of mob spawning in the undercity?</p></blockquote><p><strong>Wingzero54</strong>:</p><blockquote><p>He is suing you for damage recieved between your removal of lamps and placement of torches following the original lawsuit. Your culpability in regards to all mob spawning is not on trial here</p></blockquote><p><strong>TheOrangeWizard</strong>:</p><blockquote><p>I was given 2(?) weeks to place torches, I don&#39;t see why I should be punished for following my sentence.</p></blockquote><p><strong>Wingzero54</strong>:</p><blockquote><p>No time frame was given by the court to place torches</p></blockquote><blockquote><p>May 28th is when Bg gave the final decision from your appeal. When did you torch the undercity, Orange?</p></blockquote><blockquote><p>June 3rd is when Meat&#39;s original suit for you to pay armor reps was placed</p></blockquote><p><strong>TheOrangeWizard</strong>:</p><blockquote><p>I forget exactly</p></blockquote><p><strong>meat312</strong>:</p><blockquote><p>He did not torch the undercity.</p></blockquote><blockquote><p>there dark places everywhere. If he did torch it, it was such low quality that it may as well have not been.</p></blockquote><p><strong>Wingzero54</strong>:</p><blockquote><p>TheOrangeWizard, go through the undercity and finish placing torches in all the dark areas in the next 48 hours.</p></blockquote><blockquote><p>I will check it out Sunday [10th June] to verify the work has been done.</p></blockquote><blockquote><p>And pay meat312 4d for damages from mob spawning. I find that a more fair amount</p></blockquote><blockquote><p>Let&#39;s try to get this resolved, gentlemen, so we don&#39;t have to see you two in here again</p></blockquote>',33),i=[r];function s(c,d,p,l,h,u){return o(),t("div",null,i)}const b=e(n,[["render",s]]);export{m as __pageData,b as default};
